changeSet.sql:
DROP TABLE IF EXISTS user_assigned_vendors;
CREATE TABLE user_assigned_vendors
(
	id serial,
	user_id integer DEFAULT NULL,
	vendor_id integer DEFAULT NULL,
	CONSTRAINT pk_user_assigned_vendors PRIMARY KEY (id)
	, CONSTRAINT fk_user_assigned_vendors_to_vendor FOREIGN KEY (vendor_id) REFERENCES organizations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_user_assigned_vendors_to_user FOREIGN KEY (user_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_user_assigned_vendors_user ON user_assigned_vendors (user_id);
CREATE INDEX i_user_assigned_vendors_vendor ON user_assigned_vendors (vendor_id);
CREATE UNIQUE INDEX ui_user_assigned_vendors_vendor_user ON user_assigned_vendors (vendor_id, user_id);
